def checkout_process(cart_items, discount_code, user, payment_info):
    def validate_cart(cart_items):
        if not cart_items:
            raise ValueError("Cart is empty.")
        for item in cart_items:
            if item['quantity'] <= 0:
                raise ValueError(f"Invalid quantity for item {item['id']}.")
